const [open, setOpen] = React.useState(false);
const images = [
  'https://i.pinimg.com/originals/d8/bd/b4/d8bdb45a931b4265bec8e8d3f15021bf.jpg',
  'https://i.pinimg.com/originals/c2/31/a0/c231a069c5e24099723564dae736f438.jpg',
];

<Button onClick={() => setOpen(true)}>Open gallery</Button>
<Gallery open={open} onOpenChange={setOpen}>
  {images.map((image, index) => (
    <GalleryItem key={index} {...getGalleryItemImage({src: image, name: image})} />
  ))}
</Gallery>

const {data, fetchNextPage} = useFeedQuery();
const isAllPostsShown = data.posts.length === data.total;

<InfiniteScroll onActivate={fetchNextPage} disabled={isAllPostsShown}>
  {data.posts.map((post) => (
    <Post key={post.id} post={post} />
  ))}
</InfiniteScroll>

