const options: ReactionProps[] = [
  {content: '👍', value: 'thumbs-up'},
  {content: '😎', value: 'cool'},
];
const [usersReacted, setUsersReacted] = React.useState({'cool': [currentUser]});
const reactionsState = Object.entries(usersReacted).map(([value, users]) => ({
  value, counter: users.length, selected: users.some(u => u.name === currentUser.name),
}));

<Reactions reactions={options} reactionsState={reactionsState} onToggle={onToggle} />
